import json
import re
from dataclasses import dataclass
from pathlib import Path
from typing import Dict, List, Tuple

import torch
from peft import PeftModel
from transformers import AutoProcessor, Qwen2_5_VLForConditionalGeneration

GRID_SIZE = 1000.0
DEFAULT_MIN_PIXELS = 256 * 28 * 28
DEFAULT_MAX_PIXELS = 512 * 28 * 28
FALLBACK_BASE_MODEL_DIR = Path("/data/base_model/Qwen2.5-VL-3B-Instruct")


@dataclass
class ParsedPrediction:
    kind: str
    values: List[float]
    raw_text: str = ""


def _has_model_weights(path: Path) -> bool:
    if not path.exists() or not path.is_dir():
        return False
    weight_names = [
        "model.safetensors",
        "model.safetensors.index.json",
        "pytorch_model.bin",
        "pytorch_model.bin.index.json",
    ]
    return any((path / name).exists() for name in weight_names)


def _candidate_base_dirs(ckpt_dir: Path) -> List[Path]:
    cands: List[Path] = []
    cands.append(ckpt_dir / "base_model")
    cands.append(ckpt_dir.parent / "baseline" / "base_model")

    meta_path = ckpt_dir / "meta.json"
    if meta_path.exists():
        try:
            meta = json.loads(meta_path.read_text())
            base = meta.get("base_model_dir")
            if base:
                base_path = Path(base)
                cands.append(base_path if base_path.is_absolute() else (ckpt_dir / base_path))
        except Exception:
            pass

    cands.append(FALLBACK_BASE_MODEL_DIR)
    uniq = []
    seen = set()
    for p in cands:
        rp = str(p)
        if rp not in seen:
            seen.add(rp)
            uniq.append(p)
    return uniq


def resolve_base_model_dir(checkpoint: str) -> str:
    ckpt_dir = Path(checkpoint)
    if ckpt_dir.is_file():
        ckpt_dir = ckpt_dir.parent
    for cand in _candidate_base_dirs(ckpt_dir):
        if _has_model_weights(cand):
            return str(cand)
    raise FileNotFoundError(f"Could not find packaged base model for checkpoint {checkpoint}")


def load_processor(checkpoint_or_model_dir: str, min_pixels: int = DEFAULT_MIN_PIXELS, max_pixels: int = DEFAULT_MAX_PIXELS):
    p = Path(checkpoint_or_model_dir)
    proc_dir = p / "processor"
    use_dir = proc_dir if proc_dir.exists() else p
    return AutoProcessor.from_pretrained(
        str(use_dir),
        local_files_only=True,
        min_pixels=min_pixels,
        max_pixels=max_pixels,
        trust_remote_code=False,
    )


def row_to_point(row: Dict) -> Tuple[float, float]:
    if row.get("target_point") is not None:
        return float(row["target_point"][0]), float(row["target_point"][1])
    x1, y1, x2, y2 = row["target_bbox"]
    return float((x1 + x2) / 2.0), float((y1 + y2) / 2.0)


def target_to_text(row: Dict, grid_size: int = int(GRID_SIZE)) -> str:
    w = max(float(row["image_width"]), 1.0)
    h = max(float(row["image_height"]), 1.0)
    x, y = row_to_point(row)
    gx = int(round(x / w * grid_size))
    gy = int(round(y / h * grid_size))
    gx = max(0, min(grid_size, gx))
    gy = max(0, min(grid_size, gy))
    return f"<point>{gx} {gy}</point>"


def build_messages(row: Dict):
    instruction = row["instruction"].strip()
    return [
        {
            "role": "system",
            "content": [
                {
                    "type": "text",
                    "text": "You are a GUI grounding assistant. Output only one point in the exact format <point>x y</point> using a 0-1000 coordinate grid.",
                }
            ],
        },
        {
            "role": "user",
            "content": [
                {"type": "image", "image": row["image"]},
                {"type": "text", "text": instruction},
            ],
        },
    ]


def _extract_numbers(text: str) -> List[float]:
    return [float(x) for x in re.findall(r"-?\d+(?:\.\d+)?", text)]


def clip_point(x: float, y: float, w: float, h: float) -> List[float]:
    return [float(min(max(x, 0.0), w)), float(min(max(y, 0.0), h))]


def scale_grid_to_abs(vals: List[float], image_width: float, image_height: float, grid_size: float = GRID_SIZE) -> List[float]:
    return [vals[0] * image_width / grid_size, vals[1] * image_height / grid_size]


def parse_prediction_text(text: str, image_width: float, image_height: float) -> ParsedPrediction:
    raw = (text or "").strip()
    lower = raw.lower()

    patterns = [
        r"<point>\s*([0-9]+(?:\.[0-9]+)?)\s*[ ,]\s*([0-9]+(?:\.[0-9]+)?)\s*</point>",
        r"<point>\s*([0-9]+(?:\.[0-9]+)?)\s+([0-9]+(?:\.[0-9]+)?)\s*</point>",
        r"<point[^>]*x\s*=\s*\"?([0-9]+(?:\.[0-9]+)?)\"?[^>]*y\s*=\s*\"?([0-9]+(?:\.[0-9]+)?)\"?[^>]*>",
        r"<point[^>]*x1\s*=\s*\"?([0-9]+(?:\.[0-9]+)?)\"?[^>]*y1\s*=\s*\"?([0-9]+(?:\.[0-9]+)?)\"?[^>]*>",
        r"point\s*[:=]\s*\(?\s*([0-9]+(?:\.[0-9]+)?)\s*[, ]\s*([0-9]+(?:\.[0-9]+)?)\s*\)?",
    ]
    for pat in patterns:
        m = re.search(pat, lower, flags=re.S)
        if m:
            vals = [float(m.group(1)), float(m.group(2))]
            if max(vals) <= 1.5:
                x, y = vals[0] * image_width, vals[1] * image_height
            elif max(vals) <= GRID_SIZE + 5:
                x, y = scale_grid_to_abs(vals, image_width, image_height)
            else:
                x, y = vals[0], vals[1]
            return ParsedPrediction("point", clip_point(x, y, image_width, image_height), raw)

    nums = _extract_numbers(lower)
    if len(nums) >= 2:
        vals = nums[:2]
        if max(vals) <= 1.5:
            x, y = vals[0] * image_width, vals[1] * image_height
        elif max(vals) <= GRID_SIZE + 5:
            x, y = scale_grid_to_abs(vals, image_width, image_height)
        else:
            x, y = vals[0], vals[1]
        return ParsedPrediction("point", clip_point(x, y, image_width, image_height), raw)

    return ParsedPrediction("point", [image_width / 2.0, image_height / 2.0], raw)


def load_model_for_inference(checkpoint: str, min_pixels: int = DEFAULT_MIN_PIXELS, max_pixels: int = DEFAULT_MAX_PIXELS):
    ckpt_dir = Path(checkpoint)
    if ckpt_dir.is_file():
        ckpt_dir = ckpt_dir.parent

    base_dir = resolve_base_model_dir(str(ckpt_dir))
    processor = load_processor(str(ckpt_dir), min_pixels=min_pixels, max_pixels=max_pixels)
    device_map = "cuda:0" if torch.cuda.is_available() else "cpu"
    dtype = torch.bfloat16 if torch.cuda.is_available() else torch.float32

    base_model = Qwen2_5_VLForConditionalGeneration.from_pretrained(
        base_dir,
        local_files_only=True,
        torch_dtype=dtype,
        device_map=device_map,
        trust_remote_code=False,
    )
    model = PeftModel.from_pretrained(base_model, str(ckpt_dir), local_files_only=True)
    model.eval()
    return model, processor


def generate_prediction(model, processor, image, instruction: str, image_width: float, image_height: float) -> Dict:
    row = {"instruction": instruction, "image": image}
    messages = build_messages(row)
    text = processor.apply_chat_template(messages, tokenize=False, add_generation_prompt=True)

    device = next(model.parameters()).device
    inputs = processor(text=[text], images=[image], padding=True, return_tensors="pt")
    inputs = {k: (v.to(device) if hasattr(v, "to") else v) for k, v in inputs.items()}

    with torch.no_grad():
        out_ids = model.generate(
            **inputs,
            max_new_tokens=16,
            do_sample=False,
            use_cache=True,
        )
    gen_ids = out_ids[:, inputs["input_ids"].shape[1]:]
    pred_text = processor.batch_decode(gen_ids, skip_special_tokens=True, clean_up_tokenization_spaces=False)[0]
    parsed = parse_prediction_text(pred_text, float(image_width), float(image_height))
    return {"point": parsed.values, "raw_text": parsed.raw_text}
